def moebius(n):
    n = abs(int(n))
    if n < 2:
        return n
    factors = []
    for p in xrange(2, n + 1):
        if not n % p:
            if not n % p ** 2:
                return 0
            if not sum((p % f for f in factors)):
                factors.append(p)
    return (-1) ** len(factors)

