    elongated_cds = {'start': cds['start'], 'stop': cds['stop'], 'strand': cds['strand'], 'edge': cds.get('edge', False), 'elongation_upstream': offset, 'elongation_downstream': offset}
    sequence_length = len(sequence['nt'])
