            elongated_cds['edge'] = True
        else:
            elongated_cds['stop'] = sequence_length
            elongated_cds['elongation_downstream'] = sequence_length - cds['stop']
    else:
        elongated_cds['stop'] = elongated_cds['stop'] + offset
    return elongated_cds

