def _histogram_data(iterator):
    histogram_started = False
    header_passed = False
    for line in iterator:
        if '## HISTOGRAM' in line:
            histogram_started = True
        elif histogram_started:
            if header_passed:
                values = line.rstrip().split('\t')
                if len(values) == 1:
                    continue
                try:
                    (problem_type, name) = values[0].split(':')
                except ValueError:
                    log.warning("Line did not look like normal picard 'ERROR:NAME' format, ignoring: {}".format(values[0]))
                    continue
                yield (problem_type, name, int(values[1]))
            elif line.startswith('Error Type'):
                header_passed = True

