def determine_barplot_height(max_n_samples: int, max_bars_in_group: int=1, legend_height: Optional[int]=None) -> int:
    n_bars = max_n_samples
    n_bars *= max_bars_in_group

    def n_bars_to_size(n: int):
        if n >= 30:
            return 15
        if n >= 20:
            return 20
        if n >= 10:
            return 25
        if n >= 5:
            return 30
        return 35
    height = n_bars * n_bars_to_size(n_bars)
    if legend_height is not None:
        height = max(height, max(height, legend_height))
        height = min(660, max(height, legend_height))
    height += 140
    MIN_HEIGHT = 300
    MAX_HEIGHT = 2560
    height = min(MAX_HEIGHT, height)
    height = max(MIN_HEIGHT, height)
    return height

